from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import jwt
from datetime import datetime, timedelta
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Replace with your secret key
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'  # Use your database URI
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

def authenticate(username, password):
    user = User.query.filter_by(username=username).first()
    if not user or not check_password_hash(user.password, password):
        return False
    return user

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    user = authenticate(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    token = jwt.encode({'user_id': user.id, 'exp': datetime.utcnow() + timedelta(minutes=30)}, app.config['SECRET_KEY'])
    return jsonify({'token': token}), 200

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization')
        if not auth:
            return jsonify({'error': 'Missing Authorization Header'}), 401
        
        token = auth.split(" ")[1]
        try:
            data = jwt.decode(token, app.config['SECRET<｜begin▁of▁sentence｜>_KEY'])
        except:
            return jsonify({'error': 'Invalid Token'}), 401
        
        user = User.query.get(data['user_id'])
        if not user:
            return jsonify({'error': 'User Not Found'}), 401
        
        return f(*args, **kwargs)
    
    return decorated

@app.route('/protected', methods=['GET'])
@require_auth
def protected():
    return jsonify({'message': 'Access Granted!'})